            WriteLiteral(@"
<script>
    document.addEventListener(""DOMContentLoaded"", function () {
        const movementType = document.getElementById(""movementType"");
        const motifSelect = document.getElementById(""motifSelect"");

        function updateMotifOptions() {
            const selectedType = movementType.value;

            for (let i = 0; i < motifSelect.options.length; i++) {
                motifSelect.options[i].disabled = false;
            }

            if (selectedType === ""Entrée"") {
                for (let i = 0; i < motifSelect.options.length; i++) {
                    if (motifSelect.options[i].value === ""Vente client"" || motifSelect.options[i].value === ""Produit abîmé"") {
                        motifSelect.options[i].disabled = true;
                    }
                }
                motifSelect.value = ""Réapprovisionnement"";
            }
        }

        movementType.addEventListener(""change"", updateMotifOptions);
        updateMotifOptions();
    });
</script>
");
